var findKthNumber = function(m, n, k) {
    const count = (x) => {
        let total = 0;
        for (let i = 1; i <= m; i++) total += Math.min(Math.floor(x / i), n);
        return total;
    };
    let lo = 1, hi = m * n;
    while (lo < hi) {
        const mid = Math.floor((lo + hi) / 2);
        if (count(mid) >= k) hi = mid;
        else lo = mid + 1;
    }
    return lo;
};
